package com.ephirium.ephiriumBattlePass.manager;

import com.ephirium.ephiriumBattlePass.missions.Mission;
import org.bukkit.entity.Player;

import java.util.*;

public class MissionManager {

    private final Map<UUID, List<Mission>> missions = new HashMap<>();
    private final BattlePassManager battlePassManager;

    public MissionManager(BattlePassManager battlePassManager) {
        this.battlePassManager = battlePassManager;
    }

    public List<Mission> getMissions(Player player) {
        return missions.computeIfAbsent(player.getUniqueId(), k -> generateDailyMissions());
    }

    private List<Mission> generateDailyMissions() {
        List<Mission> list = new ArrayList<>();

        list.add(new Mission("mine_blocks", "BLOCK_BREAK", 800, 120));
        list.add(new Mission("kill_mobs", "KILL", 100, 120));
        list.add(new Mission("earn_money", "MONEY", 5000, 150));

        return list;
    }

    public void progress(Player player, String type, int amount) {
        for (Mission mission : getMissions(player)) {

            if (!mission.isCompleted() && mission.type.equals(type)) {
                mission.addProgress(amount);

                if (mission.isCompleted()) {
                    player.sendMessage("§6Misión completada! +" + mission.getXpReward() + " XP");
                }
            }
        }
    }
}

package com.ephirium.ephiriumBattlePass.manager;

import com.ephirium.ephiriumBattlePass.missions.Mission;
import org.bukkit.entity.Player;

import java.util.*;

public class MissionManager {

    private final Map<UUID, List<Mission>> missions = new HashMap<>();
    private final BattlePassManager battlePassManager;

    public MissionManager(BattlePassManager battlePassManager) {
        this.battlePassManager = battlePassManager;
    }

    public List<Mission> getMissions(Player player) {
        return missions.computeIfAbsent(player.getUniqueId(), k -> generateDailyMissions());
    }

    private List<Mission> generateDailyMissions() {
        List<Mission> list = new ArrayList<>();

        list.add(new Mission("mine_blocks", "BLOCK_BREAK", 800, 120));
        list.add(new Mission("kill_mobs", "KILL", 100, 120));
        list.add(new Mission("earn_money", "MONEY", 5000, 150));

        return list;
    }

    public void progress(Player player, String type, int amount) {
        for (Mission mission : getMissions(player)) {

            if (!mission.isCompleted() && mission.type.equals(type)) {
                mission.addProgress(amount);

                if (mission.isCompleted()) {
                    player.sendMessage("§6Misión completada! +" + mission.getXpReward() + " XP");
                    battlePassManager.addXP(player, mission.getXpReward());
                }
            }
        }
    }
}
